self.addEventListener("push",i=>{if(i.data){let t=i.data.json(),n={body:t.body,icon:"/icon-192.png",badge:"/icon-192.png",vibrate:[100,50,100],data:{dateOfArrival:Date.now(),primaryKey:"2",url:t.url||"/"}};i.waitUntil(self.registration.showNotification(t.title,n))}}),self.addEventListener("notificationclick",i=>{i.notification.close(),i.notification.data&&i.notification.data.url&&i.waitUntil(self.clients.matchAll({type:"window"}).then(t=>{for(let n of t)if(n.url===i.notification.data.url&&"focus"in n)return n.focus();if(self.clients.openWindow)return self.clients.openWindow(i.notification.data.url)}))});